        icon={<span>Icon</span>}
      />
    );

    expect(screen.getByText("This is a very long label that should still render properly")).toBeInTheDocument();
  });

  it("renders percentage as string", () => {
    render(
      <DashboardStatCard
        label="Completion"
        value="75%"
        icon={<span>Icon</span>}
      />
    );

    expect(screen.getByText("75%")).toBeInTheDocument();
  });

  it("renders currency as string", () => {
    render(
      <DashboardStatCard
        label="Revenue"
        value="$12,345"
        icon={<span>Icon</span>}
      />
    );

    expect(screen.getByText("$12,345")).toBeInTheDocument();
  });
});

import { describe, it, expect, vi, beforeEach } from "vitest";
import { render, screen, waitFor } from "@testing-library/react";
import PerformanceDashboard from "./PerformanceDashboard";

// Mock @tanstack/react-query
vi.mock("@tanstack/react-query", () => ({
  useQuery: vi.fn(),
}));

describe("PerformanceDashboard Component", () => {
  beforeEach(() => {
    vi.clearAllMocks();
    // Mock getBoundingClientRect for framer-motion measurements
    Element.prototype.getBoundingClientRect = vi.fn(() => ({
      width: 400,
      height: 200,
      top: 0,
      left: 0,
      bottom: 200,
      right: 400,
      x: 0,
      y: 0,
      toJSON: vi.fn(),
    }));
  });

  it("renders loading state initially", () => {
    const { useQuery } = await import("@tanstack/react-query");
