    await act(async () => {
      await result.current.handleEditorDidMount(mockEditor, mockMonaco);
    });

    // Then enable vim mode
    await act(async () => {
      result.current.setIsVimMode(true);
    });

    // Wait for dynamic import to resolve
    await waitFor(() => {
      expect(result.current.isVimMode).toBe(true);
    });

