  describe("handleLoadGist", () => {
    const mockSetFiles = vi.fn();
    const mockSetActiveFile = vi.fn();
    const mockCompileCode = vi.fn();

    beforeEach(() => {
      mockSetFiles.mockClear();
      mockSetActiveFile.mockClear();
      mockCompileCode.mockClear();
