        if (aiPlayerIdx > 0) {
          result.current.setCurrentPlayerIdx(aiPlayerIdx);
        }
      });

      // AI turn should execute automatically
      // Just verify the hook doesn't crash
      expect(result.current.isAIThinking).toBeDefined();
